      "content": "const { randomUUID } = require('node:crypto');
taskService = require('../tasks/service');

let comments = [];

function addComment(projectId, taskId, message) {
  const task = taskService.getTasks(projectId).find(t => t.id === taskId);
  if (!task) return null;
  const comment = { id: randomUUID(), projectId, taskId, message };
  comments.push(comment);
  return comment;
}

function getComments(projectId, taskId) {
  const task = taskService.getTasks(projectId).find(t => t.id === taskId);
  if (!task) return null;
  return comments.filter(c => c.projectId === projectId && c.taskId === taskId);
}

module.exports = {
  addComment,
  getComments,
};
